clc; clear; close all;
% PREPROCESS IMAGE
function img_out = preprocessImage(img)
    img_out = imresize(img, [224 224]);
    if size(img_out,3) == 1
        img_out = cat(3, img_out, img_out, img_out);
    end

    img_out = im2uint8(img_out);
end

% LOAD MODELS
fireData = load('fireModel.mat');
damageData = load('damageModel.mat');

fireNet = fireData.fireModel;
damageNet = damageData.damageModel;

% 2. LOAD IMAGE
[file, path] = uigetfile({'*.jpg;*.png'}, 'Select Test Image');

if isequal(file,0)
    disp("No image selected");
    return;
end

img_original = imread(fullfile(path, file));

figure; %[output:51aa1d12]
imshow(img_original); %[output:51aa1d12]
title("Original Image"); %[output:51aa1d12]

% Preprocess
img = preprocessImage(img_original);

% 3. FIRE MODEL OUTPUT
[label_fire, scores_fire] = classify(fireNet, img);
classes_fire = fireNet.Layers(end).Classes;

fireIdx = find(classes_fire == "1_1");

if isempty(fireIdx)
    error("Fire class '1_1' not found");
end

P_fire = scores_fire(fireIdx);

%4. DAMAGE MODEL OUTPUT
[label_damage, scores_damage] = classify(damageNet, img);
classes_damage = damageNet.Layers(end).Classes;

damageIdx = find(classes_damage == "damaged");

if isempty(damageIdx)
    error("Damage class 'damaged' not found");
end

D_score = scores_damage(damageIdx);

% 5. DECISION MAKING
Severity = 0.6 * P_fire + 0.4 * D_score;
if P_fire < 0.3 && D_score < 0.3
    status = "SAFE";
elseif P_fire < 0.5  && D_score > 0.4
    status = " DAMAGE DETECTED";
%elseif P_fire >= 0.5 && D_score >= 0.4
    %status = "ACTIVE FIRE WITH DAMAGE";
elseif P_fire >= 0.3 && D_score < 0.4
    status = "FIRE DETECTED";
else
    status = "UNCERTAIN";
end

% 6. UAV GRID MAPPING
gridSize = 16;
severityMap = zeros(gridSize);
[h, w, ~] = size(img_original);
stepH = floor(h / gridSize);
stepW = floor(w / gridSize);

for i = 1:gridSize
    for j = 1:gridSize
        
        patch = img_original((i-1)*stepH+1:i*stepH, ...
                             (j-1)*stepW+1:j*stepW, :);

        % Preprocess patch
        patch = preprocessImage(patch);

        % Fire prediction
        [~, score_f] = classify(fireNet, patch);
        P_patch_fire = score_f(fireIdx);

        %% Damage prediction
        [~, score_d] = classify(damageNet, patch);
        P_patch_damage = score_d(damageIdx);

        %% Combined severity
        severityMap(i,j) = 0.8 * P_patch_fire + 0.2 * P_patch_damage;
        %severityMap(i,j) = 0.5 * P_patch_fire + 0.5 * P_patch_damage;
    end
end

% 7. VISUALIZATION
% Heatmap
figure; %[output:9ac1d486]
imagesc(severityMap); %[output:9ac1d486]
colorbar; %[output:9ac1d486]
title('UAV Fire + Damage Severity Map'); %[output:9ac1d486]

% Overlay on original image
figure; %[output:7851afb6]
imshow(img_original); %[output:7851afb6]
hold on; %[output:7851afb6]
imagesc(severityMap, 'AlphaData', 0.5); %[output:7851afb6]
colormap jet; %[output:7851afb6]
colorbar; %[output:7851afb6]
title('UAV Overlay Severity Map'); %[output:7851afb6]

% 8. FINAL REPORT
fprintf("\n===== UAV DISASTER ANALYSIS =====\n"); %[output:0f299577]

fprintf("Fire Class        : %s\n", string(label_fire)); %[output:79aa4b42]
fprintf("Damage Class      : %s\n", string(label_damage)); %[output:7e583249]

fprintf("Fire Probability  : %.2f\n", P_fire); %[output:4aa484b0]
fprintf("Damage Probability: %.2f\n", D_score); %[output:24b2209b]

fprintf("Overall Severity  : %.2f\n", Severity); %[output:0c1014f7]
fprintf("Final Status      : %s\n", status); %[output:0da24d85]

if Severity > 0.7
    fprintf("EMERGENCY ALERT: Immediate response required!\n");
end

